import { puzzles } from './data/puzzles';
import {
  bridgeKey,
  parseBridgeKey,
  canAddBridge,
  computeCurrentCounts,
  isVictory,
  areAdjacent
} from './utils/hashiLogic';

function App() {
  const [puzzleIndex, setPuzzleIndex] = useState(0);
  const [bridges, setBridges] = useState(new Map());
  const [selectedIsland, setSelectedIsland] = useState(null);
  const [cursorIslandId, setCursorIslandId] = useState(0);
  const [errorMessage, setErrorMessage] = useState(null);
  const [victory, setVictory] = useState(false);

  const puzzle = puzzles[puzzleIndex];
  const islands = puzzle.islands;

  const resetPuzzle = useCallback(() => {
    setBridges(new Map());
    setSelectedIsland(null);
    setCursorIslandId(0);
    setErrorMessage(null);
    setVictory(false);
  }, []);

  const handlePuzzleChange = (e) => {
    const idx = parseInt(e.target.value, 10);
    setPuzzleIndex(idx);
    setBridges(new Map());
    setSelectedIsland(null);
    setCursorIslandId(0);
    setErrorMessage(null);
    setVictory(false);
  };

  const handleReset = () => {
    resetPuzzle();
  };

  const toggleBridge = useCallback((fromIsland, toIsland) => {
    const key = bridgeKey(fromIsland, toIsland);
    const current = bridges.get(key) || 0;

    if (current === 0) {
      const result = canAddBridge(islands, bridges, fromIsland, toIsland, 1);
      if (!result.valid) {
        setErrorMessage(result.error);
        return;
      }
      setErrorMessage(null);
      const newBridges = new Map(bridges);
      newBridges.set(key, 1);
      setBridges(newBridges);
      if (isVictory(islands, newBridges)) {
        setVictory(true);
      }
    } else if (current === 1) {
      const result = canAddBridge(islands, bridges, fromIsland, toIsland, 1);
      if (!result.valid) {
        setErrorMessage(result.error);
        return;
      }
      setErrorMessage(null);
      const newBridges = new Map(bridges);
      newBridges.set(key, 2);
      setBridges(newBridges);
      if (isVictory(islands, newBridges)) {
        setVictory(true);
      }
    } else {
      setErrorMessage(null);
      const newBridges = new Map(bridges);
      newBridges.delete(key);
      setBridges(newBridges);
      setVictory(false);
    }
  }, [bridges, islands]);

  const removeBridge = useCallback((fromIsland, toIsland) => {
    const key = bridgeKey(fromIsland, toIsland);
    const current = bridges.get(key) || 0;
    if (current > 0) {
      setErrorMessage(null);
      const newBridges = new Map(bridges);
      newBridges.delete(key);
      setBridges(newBridges);
      setVictory(false);
    }
  }, [bridges]);

  const handleIslandClick = (island, e) => {
    if (e.ctrlKey || e.button === 2) {
      if (selectedIsland !== null && selectedIsland.id !== island.id) {
        removeBridge(selectedIsland, island);
        setSelectedIsland(null);
        setCursorIslandId(island.id);
      }
      return;
    }

    if (selectedIsland === null) {
      setSelectedIsland(island);
      setCursorIslandId(island.id);
    } else if (selectedIsland.id === island.id) {
      setSelectedIsland(null);
    } else {
      toggleBridge(selectedIsland, island);
      setSelectedIsland(null);
      setCursorIslandId(island.id);
    }
  };

  const handleBridgeRightClick = (e, key) => {
    e.preventDefault();
    const current = bridges.get(key) || 0;
    if (current > 0) {
      setErrorMessage(null);
      const newBridges = new Map(bridges);
      newBridges.delete(key);
      setBridges(newBridges);
      setVictory(false);
    }
  };

  const handleBridgeCtrlClick = (e, key) => {
    if (e.ctrlKey) {
      e.preventDefault();
      const current = bridges.get(key) || 0;
      if (current > 0) {
        setErrorMessage(null);
        const newBridges = new Map(bridges);
        newBridges.delete(key);
        setBridges(newBridges);
        setVictory(false);
      }
    }
  };

  useEffect(() => {
    const handleKeyDown = (e) => {
      const currentIsland = islands.find(i => i.id === cursorIslandId);
      if (!currentIsland) return;

      if (e.key === 'Escape') {
        setSelectedIsland(null);
        setErrorMessage(null);
        return;
      }

      if (e.key === 'Enter') {
        if (selectedIsland === null) {
          setSelectedIsland(currentIsland);
        } else if (selectedIsland.id === currentIsland.id) {
          setSelectedIsland(null);
        } else {
          toggleBridge(selectedIsland, currentIsland);
          setSelectedIsland(null);
        }
        return;
      }

      let candidates = [];
      if (e.key === 'ArrowRight') {
        candidates = islands.filter(i => i.x > currentIsland.x);
      } else if (e.key === 'ArrowLeft') {
        candidates = islands.filter(i => i.x < currentIsland.x);
      } else if (e.key === 'ArrowDown') {
        candidates = islands.filter(i => i.y > currentIsland.y);
      } else if (e.key === 'ArrowUp') {
        candidates = islands.filter(i => i.y < currentIsland.y);
      } else {
        return;
      }

      candidates.sort((a, b) => {
        const da = Math.abs(a.x - currentIsland.x) + Math.abs(a.y - currentIsland.y);
        const db = Math.abs(b.x - currentIsland.x) + Math.abs(b.y - currentIsland.y);
        return da - db;
      });

      if (candidates.length > 0) {
        setCursorIslandId(candidates[0].id);
        e.preventDefault();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [cursorIslandId, selectedIsland, islands, toggleBridge]);

  const handleContextMenu = (e) => {
    e.preventDefault();
  };

  const renderBridges = () => {
    const lines = [];
    for (const [key, count] of bridges) {
      if (count === 0) continue;
      const [a, b] = parseBridgeKey(key);
      const x1 = a.x * 40;
      const y1 = a.y * 40;
      const x2 = b.x * 40;
      const y2 = b.y * 40;

      if (count === 1) {
        lines.push(
          <line
            key={key}
            x1={x1} y1={y1} x2={x2} y2={y2}
            stroke="#0f0"
            strokeWidth="2"
            onContextMenu={(e) => handleBridgeRightClick(e, key)}
            onClick={(e) => handleBridgeCtrlClick(e, key)}
            style={{ cursor: 'pointer' }}
          />
        );
      } else if (count === 2) {
        const isHorizontal = y1 === y2;
        const offset = 3;
        if (isHorizontal) {
          lines.push(
            <line
              key={key + '_a'}
              x1={x1} y1={y1 - offset} x2={x2} y2={y2 - offset}
              stroke="#0f0"
              strokeWidth="2"
              onContextMenu={(e) => handleBridgeRightClick(e, key)}
              onClick={(e) => handleBridgeCtrlClick(e, key)}
              style={{ cursor: 'pointer' }}
            />
          );
          lines.push(
            <line
              key={key + '_b'}
              x1={x1} y1={y1 + offset} x2={x2} y2={y2 + offset}
              stroke="#0f0"
              strokeWidth="2"
              onContextMenu={(e) => handleBridgeRightClick(e, key)}
              onClick={(e) => handleBridgeCtrlClick(e, key)}
              style={{ cursor: 'pointer' }}
            />
          );
        } else {
          lines.push(
            <line
              key={key + '_a'}
              x1={x1 - offset} y1={y1} x2={x2 - offset} y2={y2}
              stroke="#0f0"
              strokeWidth="2"
              onContextMenu={(e) => handleBridgeRightClick(e, key)}
              onClick={(e) => handleBridgeCtrlClick(e, key)}
              style={{ cursor: 'pointer' }}
            />
          );
          lines.push(
            <line
              key={key + '_b'}
              x1={x1 + offset} y1={y1} x2={x2 + offset} y2={y2}
              stroke="#0f0"
              strokeWidth="2"
              onContextMenu={(e) => handleBridgeRightClick(e, key)}
              onClick={(e) => handleBridgeCtrlClick(e, key)}
              style={{ cursor: 'pointer' }}
            />
          );
        }
      }
    }
    return lines;
  };

  const renderIslands = () => {
    return islands.map(island => {
      const cx = island.x * 40;
      const cy = island.y * 40;
      const isSelected = selectedIsland && selectedIsland.id === island.id;

      return (
        <g key={island.id}>
          <circle
            cx={cx}
            cy={cy}
            r={16}
            fill="black"
            stroke={isSelected ? "#ff0" : "#0f0"}
            strokeWidth={isSelected ? 3 : 2}
            onClick={(e) => handleIslandClick(island, e)}
            onContextMenu={(e) => {
              e.preventDefault();
              if (selectedIsland && selectedIsland.id !== island.id) {
                removeBridge(selectedIsland, island);
                setSelectedIsland(null);
                setCursorIslandId(island.id);
              }
            }}
            style={{ cursor: 'pointer' }}
          />
          <text
            x={cx}
            y={cy}
            textAnchor="middle"
            dominantBaseline="central"
            fill="#0f0"
            fontSize="14"
            fontFamily="monospace"
            style={{ pointerEvents: 'none' }}
          >
            {island.value}
          </text>
        </g>
      );
    });
  };

  const renderCursor = () => {
    const island = islands.find(i => i.id === cursorIslandId);
    if (!island) return null;
    const cx = island.x * 40;
    const cy = island.y * 40;
    return (
      <rect
        x={cx - 20}
        y={cy - 20}
        width={40}
        height={40}
        fill="none"
        stroke="#0ff"
        strokeWidth="2"
        strokeDasharray="4 2"
        style={{ pointerEvents: 'none' }}
      />
    );
  };

  return (
    <div style={{ background: 'black', minHeight: '100vh', padding: 0, margin: 0 }}>
      <div style={{ padding: '10px', fontFamily: 'monospace', color: '#0f0' }}>
        <select
          value={puzzleIndex}
          onChange={handlePuzzleChange}
          style={{ background: 'black', color: '#0f0', border: '1px solid #0f0', fontFamily: 'monospace', marginRight: '10px' }}
        >
          {puzzles.map((p, idx) => (
            <option key={p.id} value={idx}>{p.name}</option>
          ))}
        </select>
        <button
          onClick={handleReset}
          style={{ background: 'black', color: '#0f0', border: '1px solid #0f0', fontFamily: 'monospace', cursor: 'pointer' }}
        >
          Reset
        </button>
      </div>
      {errorMessage && (
        <div className="error-message" style={{ color: '#f00', fontFamily: 'monospace', padding: '5px 10px' }}>
          {errorMessage}
        </div>
      )}
      {victory && (
        <div className="victory-banner" style={{ color: '#0f0', fontFamily: 'monospace', padding: '5px 10px', fontSize: '24px', fontWeight: 'bold' }}>
          SOLVED!
        </div>
      )}
      <svg
        width={800}
        height={600}
        style={{ display: 'block' }}
        onContextMenu={handleContextMenu}
      >
        {renderBridges()}
        {renderIslands()}
        {renderCursor()}
      </svg>
    </div>
  );
}

export default App;
'''

