      if (isVictory(islands, newBridges)) {
        setVictory(true);
      }
    } else {
      setErrorMessage(null);
      const newBridges = new Map(bridges);
      newBridges.delete(key);
      setBridges(newBridges);
      setVictory(false);
    }
  }, [bridges, islands]);

