// Check if two islands are adjacent (same row or col, no island between them)
export function areAdjacent(islands, from, to) {
  if (from.x !== to.x && from.y !== to.y) return false;
  if (from.x === to.x && from.y === to.y) return false;

  // Check no island between them
  for (const island of islands) {
    if (island.id === from.id || island.id === to.id) continue;
    if (from.x === to.x && island.x === from.x) {
      const minY = Math.min(from.y, to.y);
      const maxY = Math.max(from.y, to.y);
      if (island.y > minY && island.y < maxY) return false;
    }
    if (from.y === to.y && island.y === from.y) {
      const minX = Math.min(from.x, to.x);
      const maxX = Math.max(from.x, to.x);
      if (island.x > minX && island.x < maxX) return false;
    }
  }
  return true;
}

// Check if a bridge between a and b would cross any existing bridge
export function wouldCross(bridges, a, b) {
  for (const [key, count] of bridges) {
    if (count === 0) continue;
    const [c, d] = parseBridgeKey(key);
    if (segmentsCross(a, b, c, d)) return true;
  }
  return false;
}

// Check if two segments cross (one horizontal, one vertical)
function segmentsCross(a, b, c, d) {
  // Determine orientation of each segment
  const seg1Horizontal = a.y === b.y;
  const seg1Vertical = a.x === b.x;
  const seg2Horizontal = c.y === d.y;
  const seg2Vertical = c.x === d.x;

  // Only perpendicular segments can cross
  if (seg1Horizontal && seg2Vertical) {
    return checkPerpendicularCross(a, b, c, d);
  }
  if (seg1Vertical && seg2Horizontal) {
    return checkPerpendicularCross(c, d, a, b);
  }

  // Parallel segments - check collinear overlap
  if (seg1Horizontal && seg2Horizontal) {
    if (a.y !== c.y) return false;
    const min1 = Math.min(a.x, b.x);
    const max1 = Math.max(a.x, b.x);
    const min2 = Math.min(c.x, d.x);
    const max2 = Math.max(c.x, d.x);
    // Overlap if ranges intersect (exclusive of endpoints)
    return min1 < max2 && min2 < max1 && !(max1 === min2 || max2 === min1);
  }
  if (seg1Vertical && seg2Vertical) {
    if (a.x !== c.x) return false;
    const min1 = Math.min(a.y, b.y);
    const max1 = Math.max(a.y, b.y);
    const min2 = Math.min(c.y, d.y);
    const max2 = Math.max(c.y, d.y);
    return min1 < max2 && min2 < max1 && !(max1 === min2 || max2 === min1);
  }

  return false;
}

// h is horizontal segment (h1, h2), v is vertical segment (v1, v2)
function checkPerpendicularCross(h1, h2, v1, v2) {
  const hY = h1.y;
  const hMinX = Math.min(h1.x, h2.x);
  const hMaxX = Math.max(h1.x, h2.x);
  const vX = v1.x;
  const vMinY = Math.min(v1.y, v2.y);
  const vMaxY = Math.max(v1.y, v2.y);

  // Cross if vX is strictly between hMinX and hMaxX
  // and hY is strictly between vMinY and vMaxY
  return vX > hMinX && vX < hMaxX && hY > vMinY && hY < vMaxY;
}

// Compute current bridge counts per island
export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const island of islands) {
    counts.set(island.id, 0);
  }

  for (const [key, count] of bridges) {
    if (count === 0) continue;
    const [a, b] = parseBridgeKey(key);
    // Find islands at these positions
    for (const island of islands) {
      if (island.x === a.x && island.y === a.y) {
        counts.set(island.id, (counts.get(island.id) || 0) + count);
      }
      if (island.x === b.x && island.y === b.y) {
        counts.set(island.id, (counts.get(island.id) || 0) + count);
      }
    }
  }
  return counts;
}

// Check if adding delta bridges between from and to is valid
export function canAddBridge(islands, bridges, from, to, delta) {
  // Check adjacency
  if (!areAdjacent(islands, from, to)) {
    return { valid: false, error: "Cannot connect non-adjacent islands" };
  }

  const key = bridgeKey(from, to);
  const current = bridges.get(key) || 0;
  const newCount = current + delta;

  // Check max 2
  if (newCount > 2) {
    return { valid: false, error: "Max 2 bridges per pair" };
  }

  // Check island capacity
  const counts = computeCurrentCounts(islands, bridges);
  const fromCount = counts.get(from.id) || 0;
  const toCount = counts.get(to.id) || 0;

  if (fromCount + delta > from.value) {
    return { valid: false, error: "Island would exceed its number" };
  }
  if (toCount + delta > to.value) {
    return { valid: false, error: "Island would exceed its number" };
  }

  // Check crossing - only need to check if adding (not removing)
  if (delta > 0 && current === 0) {
    // New bridge - check crossing with existing bridges
    const tempBridges = new Map(bridges);
    tempBridges.delete(key); // exclude self
    if (wouldCross(tempBridges, from, to)) {
      return { valid: false, error: "Bridges would cross" };
    }
  }

  return { valid: true, error: null };
}

// Check connectivity - all islands with at least one bridge must be connected
export function checkConnectivity(islands, bridges) {
  if (islands.length === 0) return true;

  // Build adjacency from bridges
  const adj = new Map();
  for (const island of islands) {
    adj.set(island.id, []);
  }

  for (const [key, count] of bridges) {
    if (count === 0) continue;
    const [a, b] = parseBridgeKey(key);
    let fromIsland = null, toIsland = null;
    for (const island of islands) {
      if (island.x === a.x && island.y === a.y) fromIsland = island;
      if (island.x === b.x && island.y === b.y) toIsland = island;
    }
    if (fromIsland && toIsland) {
      adj.get(fromIsland.id).push(toIsland.id);
      adj.get(toIsland.id).push(fromIsland.id);
    }
  }

  // BFS from first island
  const visited = new Set();
  const queue = [islands[0].id];
  visited.add(islands[0].id);

  while (queue.length > 0) {
    const curr = queue.shift();
    for (const neighbor of adj.get(curr)) {
      if (!visited.has(neighbor)) {
        visited.add(neighbor);
        queue.push(neighbor);
      }
    }
  }

  return visited.size === islands.length;
}

// Check victory condition
export function isVictory(islands, bridges) {
  const counts = computeCurrentCounts(islands, bridges);

  // Every island must have exactly its value in bridges
  for (const island of islands) {
    if ((counts.get(island.id) || 0) !== island.value) return false;
  }

  // Check connectivity
  if (!checkConnectivity(islands, bridges)) return false;

  // Check no crossings among existing bridges
  const bridgeList = [];
  for (const [key, count] of bridges) {
    if (count > 0) {
      bridgeList.push(parseBridgeKey(key));
    }
  }
  for (let i = 0; i < bridgeList.length; i++) {
    for (let j = i + 1; j < bridgeList.length; j++) {
      if (segmentsCross(bridgeList[i][0], bridgeList[i][1], bridgeList[j][0], bridgeList[j][1])) {
        return false;
      }
    }
  }

  return true;
}
