    const key = bridgeKey(fromIsland, toIsland);
    const current = bridges.get(key) || 0;

    if (current === 0) {
      const result = canAddBridge(islands, bridges, fromIsland, toIsland, 1);
      if (result.valid === false) {
        setErrorMessage(result.error);
        return;
      }
      setErrorMessage(null);
      const newBridges = new Map(bridges);
      newBridges.set(key, 1);
      setBridges(newBridges);
      if (isVictory(islands, newBridges)) {
        setVictory(true);
      }
    } else if (current === 1) {
      const result = canAddBridge(islands, bridges, fromIsland, toIsland, 1);
      if (result.valid === false) {
        setErrorMessage(result.error);
        return;
      }
      setErrorMessage(null);
      const newBridges = new Map(bridges);
      newBridges.set(key, 2);
      setBridges(newBridges);
      if (isVictory(islands, newBridges)) {
        setVictory(true);
      }
    } else {
      setErrorMessage(null);
      const newBridges = new Map(bridges);
      newBridges.delete(key);
      setBridges(newBridges);
      setVictory(false);
    }
  }, [bridges, islands]);

  const removeBridgeByKey = useCallback((key) => {
    const current = bridges.get(key) || 0;
    if (current > 0) {
      setErrorMessage(null);
      const newBridges = new Map(bridges);
      newBridges.delete(key);
      setBridges(newBridges);
      setVictory(false);
    }
  }, [bridges]);

  const handleIslandClick = (island, e) => {
    // Left click only for island selection/toggle
    if (selectedIsland === null) {
      setSelectedIsland(island);
      setCursorIslandId(island.id);
    } else if (selectedIsland.id === island.id) {
      setSelectedIsland(null);
    } else {
      toggleBridge(selectedIsland, island);
      setSelectedIsland(null);
      setCursorIslandId(island.id);
    }
  };

  // Keyboard navigation
  useEffect(() => {
    const handleKeyDown = (e) => {
      const currentIsland = islands.find(i => i.id === cursorIslandId);
      if (currentIsland == null) return;

      if (e.key === 'Escape') {
        setSelectedIsland(null);
        setErrorMessage(null);
        return;
      }

      if (e.key === 'Enter') {
        if (selectedIsland === null) {
          setSelectedIsland(currentIsland);
        } else if (selectedIsland.id === currentIsland.id) {
          setSelectedIsland(null);
        } else {
          toggleBridge(selectedIsland, currentIsland);
          setSelectedIsland(null);
        }
        return;
      }

      let candidates = [];
      if (e.key === 'ArrowRight') {
        candidates = islands.filter(i => i.x > currentIsland.x);
      } else if (e.key === 'ArrowLeft') {
        candidates = islands.filter(i => i.x < currentIsland.x);
      } else if (e.key === 'ArrowDown') {
        candidates = islands.filter(i => i.y > currentIsland.y);
      } else if (e.key === 'ArrowUp') {
        candidates = islands.filter(i => i.y < currentIsland.y);
      } else {
